"""Targeted OpenAPI contract overrides for autogenerated handler routes.

These routes are discovered from handler metadata and route maps, but they need
explicit request-body metadata to keep the published contract truthful.
"""

from __future__ import annotations

from typing import Any


def _json_body(
    description: str,
    *,
    properties: dict[str, Any] | None = None,
    required_fields: list[str] | None = None,
    required: bool = True,
) -> dict[str, Any]:
    schema: dict[str, Any] = {"type": "object"}
    if properties:
        schema["properties"] = properties
    if required_fields:
        schema["required"] = required_fields

    return {
        "description": description,
        "required": required,
        "content": {
            "application/json": {
                "schema": schema,
            }
        },
    }


